// Memoized ProjectCard component for better performance
const ProjectCard = React.memo(({ project, onNavigate, index }) => (
  <div className='project'>
    <img
      src={project.image}
      alt={project.alt}
      loading={index < 4 ? "eager" : "lazy"}
    />
    <div className='imgcaption'>
      <p>{project.title}</p>
      <p className='tags'>{project.tags}</p>
    </div>
    <Button
      variant="dark"
      size="lg"
      onClick={() => onNavigate(project.route)}
      disabled={project.disabled}
    >
      View project
    </Button>
  </div>
));

ProjectCard.displayName = 'ProjectCard';

